<body>
  <main class="app">
    <section class="hud" aria-label="Game status">
      <div class="score-wrap">
        <span class="label">Score</span>
        <span class="score" id="score">0</span>
      </div>
      <div class="hint">Use the arrow keys to move. Press Enter or the button to restart after game over.</div>
    </section>

    <section class="board-shell">
      <div class="board-frame">
        <canvas id="game" aria-label="Snake game board"></canvas>
        <div class="overlay" id="gameOver" aria-live="polite">
          <div class="dialog">
            <h1>Game Over</h1>
            <p>Your snake crashed.</p>
            <p class="final-score" id="finalScore">Final score: 0</p>
            <button id="restart" type="button">Restart</button>
          </div>
        </div>
      </div>
    </section>
  </main>

  <script>
    const canvas = document.getElementById("game");
    const scoreEl = document.getElementById("score");
    const gameOverEl = document.getElementById("gameOver");
    const finalScoreEl = document.getElementById("finalScore");
    const restartButton = document.getElementById("restart");
    const boardFrame = document.querySelector(".board-frame");
    const ctx = canvas.getContext("2d");

    const gridCount = 20;
    const cellPadding = 1.6;
    const speedMs = 110;

    let boardSize = 0;
    let cellSize = 0;
    let lastTick = 0;
    let gameOver = false;
    let score = 0;
    let snake = [];
    let direction = { x: 1, y: 0 };
    let queuedDirection = { x: 1, y: 0 };
    let food = { x: 0, y: 0 };

    function resizeCanvas() {
      const rect = boardFrame.getBoundingClientRect();
      const size = Math.max(240, Math.floor(Math.min(rect.width, window.innerHeight * 0.72)));
      const ratio = window.devicePixelRatio || 1;

      boardSize = size;
      cellSize = boardSize / gridCount;

      canvas.width = Math.floor(boardSize * ratio);
      canvas.height = Math.floor(boardSize * ratio);
      canvas.style.width = boardSize + "px";
      canvas.style.height = boardSize + "px";
      ctx.setTransform(ratio, 0, 0, ratio, 0, 0);

      draw();
    }

    function updateScore() {
      scoreEl.textContent = String(score);
      finalScoreEl.textContent = "Final score: " + score;
    }

    function randomCell() {
      return {
        x: Math.floor(Math.random() * gridCount),
        y: Math.floor(Math.random() * gridCount)
      };
    }

    function placeFood() {
      let nextFood = randomCell();
      while (snake.some((segment) => segment.x === nextFood.x && segment.y === nextFood.y)) {
        nextFood = randomCell();
      }
      food = nextFood;
    }

    function resetGame() {
      snake = [
        { x: 4, y: 10 },
        { x: 3, y: 10 },
        { x: 2, y: 10 }
      ];
      direction = { x: 1, y: 0 };
      queuedDirection = { x: 1, y: 0 };
      score = 0;
      gameOver = false;
      lastTick = 0;
      gameOverEl.classList.remove("visible");
      updateScore();
      placeFood();
      draw();
    }

    function setGameOver() {
      gameOver = true;
      gameOverEl.classList.add("visible");
      updateScore();
      restartButton.focus();
    }

    function isOpposite(next, current) {
      return next.x === -current.x && next.y === -current.y;
    }

    function queueDirection(next) {
      if (!isOpposite(next, direction) && !isOpposite(next, queuedDirection)) {
        queuedDirection = next;
      }
    }

    function handleKey(event) {
      const map = {
        ArrowUp: { x: 0, y: -1 },
        ArrowDown: { x: 0, y: 1 },
        ArrowLeft: { x: -1, y: 0 },
        ArrowRight: { x: 1, y: 0 }
      };

      if (map[event.key]) {
        event.preventDefault();
        if (!gameOver) {
          queueDirection(map[event.key]);
        }
        return;
      }

      if ((event.key === "Enter" || event.key === " ") && gameOver) {
        event.preventDefault();
        resetGame();
      }
    }

    function tick() {
      if (gameOver) {
        return;
      }

      direction = queuedDirection;

      const head = snake[0];
      const nextHead = {
        x: head.x + direction.x,
        y: head.y + direction.y
      };

      const hitWall =
        nextHead.x < 0 ||
        nextHead.x >= gridCount ||
        nextHead.y < 0 ||
        nextHead.y >= gridCount;

      const hitSelf = snake.some((segment) => segment.x === nextHead.x && segment.y === nextHead.y);

      if (hitWall || hitSelf) {
        setGameOver();
        draw();
        return;
      }

      snake.unshift(nextHead);

      if (nextHead.x === food.x && nextHead.y === food.y) {
        score += 1;
        updateScore();
        placeFood();
      } else {
        snake.pop();
      }

      draw();
    }

    function roundRect(x, y, width, height, radius) {
      const safeRadius = Math.min(radius, width / 2, height / 2);
      ctx.beginPath();
      ctx.moveTo(x + safeRadius, y);
      ctx.arcTo(x + width, y, x + width, y + height, safeRadius);
      ctx.arcTo(x + width, y + height, x, y + height, safeRadius);
      ctx.arcTo(x, y + height, x, y, safeRadius);
      ctx.arcTo(x, y, x + width, y, safeRadius);
      ctx.closePath();
    }

    function drawBoard() {
      ctx.clearRect(0, 0, boardSize, boardSize);
      ctx.fillStyle = "#101720";
      ctx.fillRect(0, 0, boardSize, boardSize);

      ctx.strokeStyle = "rgba(76, 91, 114, 0.42)";
      ctx.lineWidth = 1;
      for (let i = 1; i < gridCount; i += 1) {
        const offset = i * cellSize;
        ctx.beginPath();
        ctx.moveTo(offset, 0);
        ctx.lineTo(offset, boardSize);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(0, offset);
        ctx.lineTo(boardSize, offset);
        ctx.stroke();
      }
    }

    function drawFood() {
      const x = food.x * cellSize + cellPadding;
      const y = food.y * cellSize + cellPadding;
      const size = cellSize - cellPadding * 2;

      ctx.fillStyle = "rgba(245, 158, 11, 0.22)";
      ctx.beginPath();
      ctx.arc(x + size / 2, y + size / 2, size * 0.48, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = getComputedStyle(document.documentElement).getPropertyValue("--food").trim();
      roundRect(x + size * 0.14, y + size * 0.14, size * 0.72, size * 0.72, size * 0.22);
      ctx.fill();
    }

    function drawSnake() {
      snake.forEach((segment, index) => {
        const x = segment.x * cellSize + cellPadding;
        const y = segment.y * cellSize + cellPadding;
        const size = cellSize - cellPadding * 2;

        ctx.fillStyle = index === 0 ? "#6ee7b7" : "#10b981";
        roundRect(x, y, size, size, size * 0.24);
        ctx.fill();

        if (index === 0) {
          ctx.fillStyle = "#052e26";
          const eyeRadius = Math.max(1.5, size * 0.08);
          const eyeOffsetX = direction.x !== 0 ? size * 0.7 : size * 0.32;
          const secondEyeX = direction.x !== 0 ? size * 0.7 : size * 0.68;
          const eyeY1 = direction.y === 1 ? size * 0.68 : size * 0.32;
          const eyeY2 = direction.y === -1 ? size * 0.32 : size * 0.68;

          ctx.beginPath();
          ctx.arc(x + eyeOffsetX, y + eyeY1, eyeRadius, 0, Math.PI * 2);
          ctx.arc(x + secondEyeX, y + eyeY2, eyeRadius, 0, Math.PI * 2);
          ctx.fill();
        }
      });
    }

    function draw() {
      drawBoard();
      drawFood();
      drawSnake();
    }

    function loop(timestamp) {
      if (!lastTick) {
        lastTick = timestamp;
      }

      if (timestamp - lastTick >= speedMs) {
        tick();
        lastTick = timestamp;
      }

      window.requestAnimationFrame(loop);
    }

    window.addEventListener("keydown", handleKey, { passive: false });
    window.addEventListener("resize", resizeCanvas);
    restartButton.addEventListener("click", resetGame);

    resizeCanvas();
    resetGame();
    window.requestAnimationFrame(loop);
  </script>
</body>
</html>
